class CircuitBreaker:
    def __init__(self, window=10, failure_threshold=0.5, timeout=5):
        self.window = window
        self.failure_threshold = failure_threshold
        self.timeout = timeout
        self.calls = []
        self.state = 'CLOSED'
        self.open_until = 0

    def _record(self, success):
        self.calls.append(success)
        if len(self.calls) > self.window:
            self.calls.pop(0)

    def _failure_rate(self):
        if not self.calls:
            return 0
        return self.calls.count(False) / len(self.calls)

    def allow(self):
        import time
        now = time.time()
        if self.state == 'OPEN' and now >= self.open_until:
            self.state = 'HALF_OPEN'
        return self.state != 'OPEN'

    def on_success(self):
        self._record(True)
        if self.state == 'HALF_OPEN':
            self.state = 'CLOSED'

    def on_failure(self):
        import time
        self._record(False)
        if self.state == 'HALF_OPEN' or self._failure_rate() >= self.failure_threshold:
            self.state = 'OPEN'
            self.open_until = time.time() + self.timeout

# Usage:
